import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as n,e as i}from"./app-948cb496.js";const r="/assets/image-1697373903088-f90b837c.png",a="/assets/image-1697374218391-55ca7299.png",l="/assets/image-1697374434211-cb89c567.png",d="/assets/image-1697374434480-1cdea9ac.png",s="/assets/image-1697374434261-d15805c9.png",g="/assets/image-1697374435278-e7ebcb4b.png",c="/assets/image-1697374434230-bb324a95.png",o="/assets/image-1697374434671-1fb63798.png",x="/assets/image-1697374434210-9a36117c.png",p="/assets/image-1697374434306-c434afd5.png",y="/assets/image-1697374435684-723dbed6.png",f="/assets/image-1697374435559-6c54183c.png",m="/assets/image-1697374433746-df850d77.png",h="/assets/image-1697374433814-39ba406f.png",u="/assets/image-1697374433989-6b31e217.png",b="/assets/image-1697374433826-2bc6baaf.png",_="/assets/image-1697374434320-aaf5ffb1.png",z="/assets/image-1697374433909-1834c9e3.png",v="/assets/image-1697374435276-de09b6b9.png",E="/assets/image-1697374483287-b8629974.png",L={},S=i('<h1 id="linux" tabindex="-1"><a class="header-anchor" href="#linux" aria-hidden="true">#</a> Linux</h1><h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><p>创作者为Linux Torvalds也是Git创作者，同时也是世界著名黑客。主要发行版本<a href="%E5%86%85%E6%A0%B8%E9%83%BD%E6%98%AFLinux%E4%BD%86%E6%98%AF%E5%A4%96%E5%A3%B3%E4%B8%8D%E5%90%8C">^ 1</a>有<strong>Ubuntu 乌班图</strong>、<strong>RedHat 小红帽</strong>、<strong>CentOS</strong>、<strong>Debain 蝶变</strong>、<strong>FedoraSuSE</strong>、<strong>OpenSUSE 示意图</strong>。Linux主要应用领域是<strong>服务器领域</strong>和<strong>个人桌面领域</strong>。</p><h2 id="吉祥物" tabindex="-1"><a class="header-anchor" href="#吉祥物" aria-hidden="true">#</a> 吉祥物</h2><figure><img src="'+r+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="vmware虚拟机" tabindex="-1"><a class="header-anchor" href="#vmware虚拟机" aria-hidden="true">#</a> VMware虚拟机</h2><p><b style="color:#3e547d;"><strong>VMware(虚拟机) 17.0 激活码</strong></b></p><p>JU090-6039P-08409-8J0QH-2YR7F</p><p>MC60H-DWHD5-H80U9-6V85M-8280D</p><p><b style="color:#3e547d;"><strong>虚拟机快照</strong></b></p><figure><img src="'+a+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p><b style="color:#3e547d;"><strong>虚拟机克隆</strong></b></p><p>虚拟机上可以克隆Linux系统 实际上就是复制文件夹</p><p>虚拟机可以实现和主机共享同一个文件夹。<strong>在Linux世界里，一切皆文件(其把硬件都映射成文件了)</strong>，其最上层是根目录 &quot;/&quot; 然后在此目录下再创建其他的目录。</p><h2 id="目录树" tabindex="-1"><a class="header-anchor" href="#目录树" aria-hidden="true">#</a> 目录树</h2><table><thead><tr><th style="text-align:center;"><strong>目录</strong></th><th style="text-align:center;"><strong>作用</strong></th></tr></thead><tbody><tr><td style="text-align:center;">根目录（/）</td><td style="text-align:center;">Linux文件系统的顶层目录，所有其他目录和文件都从根目录开始。</td></tr><tr><td style="text-align:center;">/bin</td><td style="text-align:center;">存放系统启动和运行时所需的基本命令和二进制文件。例如，ls、cp、mv等命令都存放在这里。</td></tr><tr><td style="text-align:center;">/boot</td><td style="text-align:center;">包含用于启动Linux系统的引导文件，例如内核和引导加载程序。</td></tr><tr><td style="text-align:center;">/dev</td><td style="text-align:center;">包含设备文件，用于与系统硬件设备进行通信，例如硬盘、键盘、鼠标等。</td></tr><tr><td style="text-align:center;">/etc</td><td style="text-align:center;">存放系统全局配置文件和脚本，包括网络配置、用户管理和服务配置等。</td></tr><tr><td style="text-align:center;">/home</td><td style="text-align:center;">用户的家目录通常存放在这里，每个用户都有一个单独的子目录，用于存放其个人文件和配置。</td></tr><tr><td style="text-align:center;">/lib</td><td style="text-align:center;">包含系统所需的共享库文件，这些库文件在程序运行时被动态加载。</td></tr><tr><td style="text-align:center;">/media</td><td style="text-align:center;">用于挂载可移动媒体设备，如USB闪存驱动器、CD-ROM等。</td></tr><tr><td style="text-align:center;">/mnt</td><td style="text-align:center;">用于挂载临时文件系统，管理员可以手动挂载其他文件系统到此目录。</td></tr><tr><td style="text-align:center;">/opt</td><td style="text-align:center;">通常用于安装和存放第三方应用程序和软件包。</td></tr><tr><td style="text-align:center;">/proc</td><td style="text-align:center;">虚拟文件系统，提供有关系统进程和内核参数的信息。</td></tr><tr><td style="text-align:center;">/root</td><td style="text-align:center;">超级用户（管理员）的家目录，与普通用户的家目录不同。</td></tr><tr><td style="text-align:center;">/sbin</td><td style="text-align:center;">存放系统管理员和超级用户使用的系统管理工具，这些工具通常涉及系统维护和修复。</td></tr><tr><td style="text-align:center;">/srv</td><td style="text-align:center;">用于存放服务相关的数据文件，例如Web服务器（如Apache）的网站数据。</td></tr><tr><td style="text-align:center;">/tmp</td><td style="text-align:center;">用于存放临时文件，系统重启时该目录的内容通常会被清空。</td></tr><tr><td style="text-align:center;">/usr</td><td style="text-align:center;">存放系统用户和管理员安装的应用程序、库文件和文档等。</td></tr><tr><td style="text-align:center;">/var</td><td style="text-align:center;">存放变化频繁的数据文件，如日志文件、邮件队列和缓存文件等。</td></tr></tbody></table><h2 id="命令" tabindex="-1"><a class="header-anchor" href="#命令" aria-hidden="true">#</a> 命令</h2><table><thead><tr><th style="text-align:center;"><strong>命令</strong></th><th style="text-align:center;"><strong>使用例子</strong></th><th style="text-align:center;"><strong>解释说明</strong></th></tr></thead><tbody><tr><td style="text-align:center;">cd</td><td style="text-align:center;">cd /</td><td style="text-align:center;">/ 表示根目录 这里表示进入到根目录cd ~ 回到自己的家目录cd .. 回到当前目录的上一级目录</td></tr><tr><td style="text-align:center;">ls</td><td style="text-align:center;"></td><td style="text-align:center;">表示显示该目录下的所有文件</td></tr><tr><td style="text-align:center;">ip addr</td><td style="text-align:center;"></td><td style="text-align:center;">显示ip配置</td></tr><tr><td style="text-align:center;">pwd</td><td style="text-align:center;"></td><td style="text-align:center;">显示当前用户所在的目录</td></tr><tr><td style="text-align:center;">userdel xxx</td><td style="text-align:center;">userdel tom</td><td style="text-align:center;">删除xxx用户但是保留家目录</td></tr><tr><td style="text-align:center;">userdel -r xxx</td><td style="text-align:center;">userdel -r tom</td><td style="text-align:center;">删除xxx用户但是不保留家目录id</td></tr><tr><td style="text-align:center;">id xxx</td><td style="text-align:center;">id root</td><td style="text-align:center;">查询xxx的用户信息</td></tr><tr><td style="text-align:center;">who am i</td><td style="text-align:center;"></td><td style="text-align:center;">告诉你现在的用户名以及登录时间</td></tr><tr><td style="text-align:center;">clear</td><td style="text-align:center;"></td><td style="text-align:center;">清除屏幕内容</td></tr><tr><td style="text-align:center;">systemctl get-default</td><td style="text-align:center;"></td><td style="text-align:center;">查看运行级别</td></tr><tr><td style="text-align:center;">man 命令</td><td style="text-align:center;">man ls</td><td style="text-align:center;">显示想要查询命令的帮助文档</td></tr><tr><td style="text-align:center;">help 命令</td><td style="text-align:center;">help cd</td><td style="text-align:center;">获得shell内置命令的帮助信息</td></tr><tr><td style="text-align:center;">pwd</td><td style="text-align:center;"></td><td style="text-align:center;">显示当前工作的绝对路径</td></tr><tr><td style="text-align:center;">rm [选项] filename</td><td style="text-align:center;">rm cao.txt</td><td style="text-align:center;">删除文件选项里是 -rf 则可以删除非空目录</td></tr><tr><td style="text-align:center;">mkdir [选项] 要创建的目录名</td><td style="text-align:center;"></td><td style="text-align:center;">创建目录选项里 -p则是创建多级目录</td></tr><tr><td style="text-align:center;">rmdir 目录路径</td><td style="text-align:center;"></td><td style="text-align:center;">只能删除空目录</td></tr><tr><td style="text-align:center;">touch</td><td style="text-align:center;">touch cao.txt</td><td style="text-align:center;">创建一个空文件</td></tr><tr><td style="text-align:center;">cp [选项] source dest</td><td style="text-align:center;"></td><td style="text-align:center;">拷贝文件到指定目录选项里 -r 递归复制整个文件夹</td></tr><tr><td style="text-align:center;">less filename</td><td style="text-align:center;"></td><td style="text-align:center;">一般用来查看大文件</td></tr><tr><td style="text-align:center;">cal</td><td style="text-align:center;"></td><td style="text-align:center;">显示日期</td></tr><tr><td style="text-align:center;">history</td><td style="text-align:center;"></td><td style="text-align:center;">查看已经执行过的历史命令</td></tr><tr><td style="text-align:center;">locate xxx</td><td style="text-align:center;"></td><td style="text-align:center;">快速查找xxx文件的位置，使用前必须先执行updatedb指令</td></tr><tr><td style="text-align:center;">grep</td><td style="text-align:center;"></td><td style="text-align:center;">过滤查找 需要和管道符 | 联合使用 cat a.txt | grep -n &quot;hello&quot; 在a.txt中查找hello所在行</td></tr><tr><td style="text-align:center;">gzip</td><td style="text-align:center;">gzip /home/hello.txt</td><td style="text-align:center;">压缩文件</td></tr><tr><td style="text-align:center;">gunzip</td><td style="text-align:center;">gunzip /home/hello.txt.gz</td><td style="text-align:center;">解压缩</td></tr><tr><td style="text-align:center;">zip</td><td style="text-align:center;">zip -r myhome.zip /home/</td><td style="text-align:center;">将/home下的所有文件进行压缩成myhome.zip</td></tr><tr><td style="text-align:center;">unzip</td><td style="text-align:center;">unzip -d /opt/tmp myhome.zip</td><td style="text-align:center;">将myhome.zip 解压到/opt/tmp目录下</td></tr><tr><td style="text-align:center;">cat /etc/redhat-release</td><td style="text-align:center;"></td><td style="text-align:center;">查看CentOS的内核版本</td></tr></tbody></table><figure><img src="'+l+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+d+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+s+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+g+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+c+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+o+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+x+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+p+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+y+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+f+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+m+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+h+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+u+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+b+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+_+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+z+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="'+v+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="vim文本编辑器" tabindex="-1"><a class="header-anchor" href="#vim文本编辑器" aria-hidden="true">#</a> Vim文本编辑器</h2><p>Linux系统内置vi文本编辑器。vim具有程序编辑能力，可以看成vi的增强版。</p><figure><img src="'+E+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p><b style="color:#3e547d;"><strong>插入模式</strong></b></p><p>按下i I o O a A r R等任何一个字母之后才会进入编辑模式</p><p>按下 \\ 进入命令行模式</p><p><b style="color:#3e547d;"><strong>命令行模式</strong></b></p><p>先按下Esc再输入 ： 这个模式可以让我们完成读取 存盘 替换 离开vim</p><p>：wq 保存退出</p><p>：q 退出</p><p>：q！强制退出并且不保存</p><h2 id="远程登录linux" tabindex="-1"><a class="header-anchor" href="#远程登录linux" aria-hidden="true">#</a> 远程登录Linux</h2><p><b style="color:#3e547d;"><strong>XShell</strong></b></p><p>目前最好的远程登录到Llinux操作的软件，流畅的速度并且完美的解决了中文乱码的问题</p><p>名称：192.168.47.128[YX]</p><p>登录名：root</p><p>密码：123456</p><p><b style="color:#3e547d;"><strong>XFTP</strong></b></p><p>远程传输文件</p>',54),w=[S];function B(D,q){return e(),n("div",null,w)}const F=t(L,[["render",B],["__file","Linux.html.vue"]]);export{F as default};
